const rows = $input.all();
const brands = rows.map(row => ({
  id: row.json.ID || '',
  brandName: row.json.BrandName || '',
  category: row.json.Category || '',
  score: parseFloat(row.json.Score) || 0,
  readinessScore: parseFloat(row.json.ReadinessScore) || 0,
  phase: parseInt(row.json.Phase) || 1,
  routing: row.json.Routing || '',
  revenue: row.json.Revenue || '',
  retailer: row.json.Retailer || '',
  status: row.json.Status || '',
  roi: parseFloat(row.json.ROI) || 0
})).filter(b => b.brandName);

const summary = {
  totalBrands: brands.length,
  byPhase: {},
  byRouting: {},
  avgScore: 0
};

brands.forEach(b => {
  summary.byPhase[b.phase] = (summary.byPhase[b.phase] || 0) + 1;
  summary.byRouting[b.routing] = (summary.byRouting[b.routing] || 0) + 1;
});

if (brands.length > 0) {
  summary.avgScore = Math.round(brands.reduce((s, b) => s + b.score, 0) / brands.length);
}

return [{ json: { brands, summary, syncedAt: new Date().toISOString(), count: brands.length } }];
